        program_id TEXT,
        faculty_name TEXT,
        degree_name TEXT,
        amount NUMERIC(12, 2),
        currency TEXT,
        billing_basis TEXT,
        academic_year TEXT,
        category TEXT,
        source_seed_id TEXT,
        notes TEXT
    );

    INSERT INTO graduate_tuition_rate (
        university_id, faculty_id, department_id, program_id,
        scope_level, record_key, academic_year, currency, billing_basis,
        amount, category, notes, source_id
    )
    SELECT
        v_university_id,
        fac.id,
        NULL,
        gp.id,
        'PROGRAM',
        'bau_tuition_' || seed.program_key,
        seed.academic_year,
        seed.currency,
        seed.billing_basis,
        seed.amount,
        seed.category,
        seed.notes,
        s.id
    FROM bau_tuition_seed seed
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.program_key
    JOIN university_faculty fac ON fac.university_id = v_university_id AND fac.name = seed.faculty_name
    JOIN bau_source_seed ss ON ss.source_id = seed.source_seed_id
    JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
    ON CONFLICT (university_id, record_key) DO UPDATE SET
        faculty_id = EXCLUDED.faculty_id,
        department_id = EXCLUDED.department_id,
        program_id = EXCLUDED.program_id,
        scope_level = EXCLUDED.scope_level,
        academic_year = EXCLUDED.academic_year,
        currency = EXCLUDED.currency,
        billing_basis = EXCLUDED.billing_basis,
        amount = EXCLUDED.amount,
        category = EXCLUDED.category,
        notes = EXCLUDED.notes,
        source_id = EXCLUDED.source_id,
        updated_at = NOW();

    CREATE TEMP TABLE bau_fee_item_seed (
        record_key TEXT PRIMARY KEY,
        scope_level TEXT NOT NULL,
        fee_name TEXT NOT NULL,
        billing_basis TEXT NOT NULL,
        currency TEXT NOT NULL,
        amount NUMERIC(12, 2),
        category TEXT,
        source_seed_id TEXT NOT NULL,
        notes TEXT
    ) ON COMMIT DROP;

    INSERT INTO bau_fee_item_seed (
        record_key, scope_level, fee_name, billing_basis, currency, amount, category, source_seed_id, notes
