"notes":"downloaded_rendered_official_pdf — graduate tuition fees; official BAU PDF source accessed during normalization."}]$BAU_PROG_SRC$::jsonb) AS x(
        program_id TEXT,
        source_seed_id TEXT,
        source_role TEXT,
        source_order INTEGER,
        evidence_text TEXT,
        notes TEXT
    );

    INSERT INTO graduate_program_source (
        university_id, program_id, source_id, source_role, source_order, evidence_text, notes
    )
    SELECT
        v_university_id,
        gp.id,
        s.id,
        seed.source_role,
        seed.source_order,
        seed.evidence_text,
        seed.notes
    FROM bau_program_source_seed seed
    JOIN graduate_program gp ON gp.university_id = v_university_id AND gp.program_key = seed.program_key
    JOIN bau_source_seed ss ON ss.source_id = seed.source_seed_id
    JOIN source s ON s.university_id = v_university_id AND s.url = ss.url
    ON CONFLICT (program_id, source_id, source_role) DO UPDATE SET
        source_order = EXCLUDED.source_order,
        evidence_text = EXCLUDED.evidence_text,
        notes = EXCLUDED.notes,
        updated_at = NOW();

END $$;
